func:merge = int64[](int64[]:left, int64[]:right) {
    int64[]:result = [];
    int64:i = 0, j = 0;

    while (i < left.length && j < right.length) {
        int64:cmp = left[i] <=> right[j];

        if (cmp <= 0) {
            result.append(left[i]);
            i++;
        } else {
