## Builder Pattern

```aria
struct Config {
    host: string,
    port: i32,
    timeout: i32,
    retries: i32,
}

struct ConfigBuilder {
    host: ?string,
    port: ?i32,
    timeout: ?i32,
    retries: ?i32,
}

impl ConfigBuilder {
    pub fn new() -> ConfigBuilder {
        return ConfigBuilder {
            host: None,
            port: None,
            timeout: None,
            retries: None,
        };
    }

    pub fn host(host: string) -> ConfigBuilder {
        self.host = Some(host);
        return self;
    }

    pub fn port(port: i32) -> ConfigBuilder {
        self.port = Some(port);
        return self;
    }

    pub fn build() -> Config {
        return Config {
            host: self.host.unwrap_or("localhost"),
            port: self.port.unwrap_or(8080),
            timeout: self.timeout.unwrap_or(30),
            retries: self.retries.unwrap_or(3),
        };
    }
}

// Usage
config: Config = ConfigBuilder.new()
    .host("example.com")
    .port(443)
    .build();
```

