## Singleton Pattern

```aria
struct Logger {
    instance: ?*Logger = None,
}

impl Logger {
    pub fn get_instance() -> *Logger {
        if Logger.instance is None {
            Logger.instance = Some(alloc(Logger {
                // Initialize
            }));
        }
        return Logger.instance?;
    }

    pub fn log(message: string) {
        stdout << "[LOG] $message";
    }
}

// Usage
Logger.get_instance().log("Application started");
```

