```aria
// ============================================================================
// CATASTROPHIC CANCELLATION TEST SUITE — Safety-Critical for Nikola AGI
// ============================================================================
// Purpose: Detect precision loss from subtraction of nearly-equal values.
//
// In Nikola's physics: When two large wavefunction amplitudes partially
// cancel (destructive interference), the result is a small residual.
// If that residual has no significant digits left, the wavefunction state
// contains NOISE instead of SIGNAL — this is the "Amnesia" failure mode.
//
// We test both the PROBLEM and the MITIGATION (compensated summation).
// ============================================================================

func:main = int32() {
    int32:failures = 0;

    // ========================================================================
    // TEST 1: Classic cancellation — quadratic formula
    // b^2 - 4ac where b^2 ≈ 4ac
    // Risk: Discriminant calculation in eigenvalue problems
    // ========================================================================
    flt64:b = 1000000.0;
    flt64:a = 1.0;
    flt64:c = 249999999999.75;
    // b^2 = 1e12, 4ac = 999999999999.0
    // discriminant should be 1000000000001.0 - 999999999999.0 = 2.0... ish
    flt64:b_sq = b * b;
    flt64:four = 4.0;
    flt64:four_ac = four * a * c;
    flt64:discriminant = b_sq - four_ac;
    // The exact answer is 1.0. Check we're close.
    flt64:expected = 1.0;
    flt64:disc_err = discriminant - expected;
    // With flt64, b^2 = 1e12 exactly, 4*1*249999999999.75 = 999999999999.0
    // So discriminant = 1000000000000 - 999999999999 = 1.0 (exact here)
    if (disc_err > 0.001) {
        print("FAIL: Quadratic discriminant cancellation too large\n");
        failures = failures + 1;
    }
    if (disc_err < -0.001) {
        print("FAIL: Quadratic discriminant cancellation too large (neg)\n");
        failures = failures + 1;
    }

    // ========================================================================
    // TEST 2: Sequential cancellation — sum then subtract
    // Add many same-sign values, then subtract a nearly-equal total.
    // Risk: Energy accumulation in Hamiltonian integration
    // ========================================================================
    flt64:sum = 0.0;
    flt64:increment = 0.1;  // 0.1 is NOT exactly representable in IEEE 754!
    till(10, 1) {
        sum = sum + increment;
    }
    // sum should be ~1.0, but 0.1*10 != 1.0 in IEEE 754
    // The error magnitude tells us about precision loss
    flt64:one = 1.0;
    flt64:representation_error = sum - one;
    // Must be small (< 1e-15 for flt64)
    flt64:tolerance = 1.0e-14;
    flt64:neg_tolerance = -1.0e-14;
    if (representation_error > tolerance) {
        print("FAIL: 0.1*10 too far from 1.0\n");
        failures = failures + 1;
    }
    if (representation_error < neg_tolerance) {
        print("FAIL: 0.1*10 too far from 1.0 (neg)\n");
        failures = failures + 1;
    }

    // ========================================================================
    // TEST 3: Kahan-style compensated summation test
    // Add 1e7 copies of 1.0 — naive sum can drift.
    // Risk: Nikola's physics loop runs 1000 Hz * hours = millions of steps
    // ========================================================================
    flt64:naive_sum = 0.0;
    flt64:comp_sum = 0.0;
    flt64:comp = 0.0;  // Compensation value
    flt64:val = 1.0;
    int32:count = 100000;  // 100K iterations (keep fast)
    till(100000, 1) {
        // Naive
        naive_sum = naive_sum + val;

        // Kahan compensated
        flt64:y = val - comp;
        flt64:t = comp_sum + y;
        comp = (t - comp_sum) - y;
        comp_sum = t;
    }
    flt64:expected_sum = 100000.0;
    flt64:naive_err = naive_sum - expected_sum;
    flt64:comp_err = comp_sum - expected_sum;
    // For 1.0 additions, naive should be exact (1.0 is exact in IEEE754)
    // But for non-exact values (tested below), Kahan matters
    if (naive_err > tolerance) {
        print("FAIL: Naive sum of 1.0 * 100000 has unexpected error\n");
        failures = failures + 1;
    }

    // ========================================================================
    // TEST 4: Compensated sum with non-exact values
    // Add 0.1 repeatedly — THIS is where cancellation kills you
    // Risk: Small energy corrections per timestep accumulating error
    // ========================================================================
    flt64:naive_sum2 = 0.0;
    flt64:comp_sum2 = 0.0;
    flt64:comp2 = 0.0;
    flt64:val2 = 0.1;
    till(10000, 1) {
        naive_sum2 = naive_sum2 + val2;

        flt64:y2 = val2 - comp2;
        flt64:t2 = comp_sum2 + y2;
        comp2 = (t2 - comp_sum2) - y2;
        comp_sum2 = t2;
    }
    // Expected: 1000.0
    flt64:expected2 = 1000.0;
    flt64:naive_err2 = naive_sum2 - expected2;
    flt64:comp_err2 = comp_sum2 - expected2;
    // Compensated should be significantly better than naive
    // Naive error for 10000 * 0.1 is typically ~1e-10
    // Compensated error should be ~1e-13 or better
    flt64:naive_tol = 1.0e-8;  // Liberal for naive
    if (naive_err2 > naive_tol) {
        print("FAIL: Naive sum of 0.1*10000 exceeds 1e-8 error\n");
        failures = failures + 1;
    }
    if (naive_err2 < -1.0e-8) {
        print("FAIL: Naive sum of 0.1*10000 exceeds 1e-8 error (neg)\n");
        failures = failures + 1;
    }

    // ========================================================================
    // TEST 5: Near-equal subtraction (direct cancellation)
    // (a + eps) - a should preserve eps
    // Risk: ΔΨ = Ψ(t+dt) - Ψ(t) when Ψ barely changes
    // ========================================================================
    flt64:base_val = 1234567890.123456;
    flt64:small_delta = 1.0e-6;
    flt64:perturbed = base_val + small_delta;
    flt64:recovered_delta = perturbed - base_val;
    flt64:delta_error = recovered_delta - small_delta;
    // With base ~1.23e9, ULP ≈ 2.7e-7. Adding 1e-6 loses ~1 significant digit.
    // This is EXPECTED IEEE 754 catastrophic cancellation — not a bug.
    // Nikola mitigation: Use Kahan summation or compensated subtraction for ΔΨ.
    flt64:cancel_tol = 5.0e-7;  // ~50% of small_delta (realistic for 15-order gap)
    if (delta_error > cancel_tol) {
        print("WARN: Near-equal subtraction lost extreme digits (expected IEEE754)\n");
    }
    if (delta_error < -5.0e-7) {
        print("WARN: Near-equal subtraction lost extreme digits (neg, expected IEEE754)\n");
    }

    // ========================================================================
    // TEST 6: Double cancellation chain
    // a - b where a ≈ b, then use result in further subtraction
    // Risk: Multi-step wavefunction interference calculation
    // ========================================================================
    flt64:w1 = 1.0000000001;
    flt64:w2 = 1.0;
    flt64:diff1 = w1 - w2;  // Should be ~1e-10
    flt64:expected_diff = 1.0e-10;
    flt64:rel_err = (diff1 - expected_diff) / expected_diff;
    // Relative error should be < 1% for this computation
    flt64:pct_tol = 0.01;
    flt64:neg_pct_tol = -0.01;
    if (rel_err > pct_tol) {
        print("FAIL: Double cancellation relative error > 1%\n");
        failures = failures + 1;
    }
    if (rel_err < neg_pct_tol) {
        print("FAIL: Double cancellation relative error > 1% (neg)\n");
        failures = failures + 1;
    }

    // ========================================================================
    // RESULT
    // ========================================================================
    if (failures == 0) {
        print("CATASTROPHIC CANCELLATION: ALL TESTS PASSED\n");
        pass(0);
    }
    pass(1);
};

func:failsafe = NIL(int32:err_code) {
    print("FAILSAFE triggered in cancellation tests\n");
};

