func:compute_physics_step = flt64(flt64:x, flt64:v, flt64:dt) {
    // Simplified physics step: returns new x after one leapfrog step
    // x'' = -x (simple harmonic oscillator)
    flt64:half_dt = dt * 0.5;
    flt64:zero = 0.0;
    flt64:ax = zero - x;
    flt64:v_half = v + half_dt * ax;
    flt64:x_new = x + dt * v_half;
    flt64:ax_new = zero - x_new;
    flt64:v_new = v_half + half_dt * ax_new;
    pass(x_new);
