vec3:pos_3d = vec3(pos_2d.x, pos_2d.y, 0.0);  // Z defaults to 0.0

// vec3 → vec2 (drop Z component)
vec3:pos_3d_orig = vec3(10.0, 20.0, 30.0);
vec2:pos_2d_proj = vec2(pos_3d_orig.x, pos_3d_orig.y);  // Ignore Z
```

