// Extract octets
uint8:a = uint8((ip >> 24u32) & 0xFFu32);  // 192
uint8:b = uint8((ip >> 16u32) & 0xFFu32);  // 168
uint8:c = uint8((ip >> 8u32) & 0xFFu32);   // 1
uint8:d = uint8(ip & 0xFFu32);              // 1
