        fail(upd2.error);
    }

    int32:sum = upd1.value + upd2.value;
    pass(sum);
};

// ============================================================================
// LEVEL 5: Retry with exponential backoff pattern
// ============================================================================

func:retry_with_backoff = int32(int32:id, int32:new_val, int32:max_attempts) {
    int32:attempts = 0i32;
    int32:backoff = 1i32;

    while (attempts < max_attempts) {
        Result<int32>:result = validate_and_update(id, new_val);

        // Test: Early success return in retry loop
        if (!(result.is_error)) {
            pass(result.value);  // Success!
        }

        // Failed, increase backoff
        backoff = backoff * 2i32;
        attempts = attempts + 1i32;
    }

    fail(408i32);  // Timeout after retries
};

// ============================================================================
// LEVEL 6: Complex workflow with all operators
// ============================================================================

func:complex_workflow = int32(int32:user_id, int32:threshold) {
    int32:total = 0i32;

    // Step 1: Lookup with unwrap (? operator)
    Result<int32>:lookup = db_lookup(user_id);
    int32:user_val = lookup ? 0i32;  // Default to 0 if not found
    total = total + user_val;

    // Step 2: Conditional processing with is ternary
    int32:adjusted = is (user_val > threshold) : user_val : threshold;

    // Step 3: Batch operation
    Result<int32>:batch = batch_update(2i32, 3i32, 10i32);  // Update IDs 2,4,6
    int32:batch_count = batch ? 0i32;
    total = total + batch_count;

    // Step 4: Atomic swap
    Result<int32>:swapped = atomic_swap(2i32, 4i32);

    // Test: Pick with complex branches
    pick(swapped.is_error) {
        (false) {
            total = total + swapped.value;
        },
        (*) {
            // Swap failed, try simple update
            Result<int32>:fallback = db_update(2i32, adjusted);
            if (!(fallback.is_error)) {
                total = total + fallback.value;
            }
        }
    }

    pass(total);
};

// ============================================================================
// MAIN: Ultimate stress test
// ============================================================================

func:main = int32() {
    int32:score = 0i32;

    // Test 1: Basic lookup
    Result<int32>:r1 = db_lookup(4i32);  // Even, succeeds
    if (!(r1.is_error)) {
        score = score + 1i32;  // +1 = 1
    }

    // Test 2: Failed lookup
    Result<int32>:r2 = db_lookup(5i32);  // Odd, fails
    if (r2.is_error) {
        score = score + 1i32;  // +1 = 2
    }

    // Test 3: Validate and update
    Result<int32>:r3 = validate_and_update(2i32, 300i32);  // 2 exists (200), update to 300
    if (!(r3.is_error)) {
        score = score + 1i32;  // +1 = 3
    }

    // Test 4: Bad update (decrease)
    Result<int32>:r4 = validate_and_update(2i32, 100i32);  // Trying to decrease
    if (r4.is_error) {
        score = score + 1i32;  // +1 = 4 (correctly failed)
    }

    // Test 5: Batch update
    Result<int32>:r5 = batch_update(2i32, 4i32, 10i32);  // IDs 2,3,4,5 - even ones succeed
    int32:batch_result = r5 ? 0i32;
    score = score + batch_result;  // +2 = 6 (IDs 2,4 succeeded)

    // Test 6: Atomic swap
    Result<int32>:r6 = atomic_swap(2i32, 4i32);
    if (!(r6.is_error)) {
        score = score + 1i32;  // +1 = 7
    }

    // Test 7: Retry with backoff
    Result<int32>:r7 = retry_with_backoff(6i32, 700i32, 3i32);
    if (!(r7.is_error)) {
        score = score + 1i32;  // +1 = 8
    }

    // Test 8: Complex workflow
    Result<int32>:r8 = complex_workflow(2i32, 100i32);
    if (!(r8.is_error)) {
        score = score + 1i32;  // +1 = 9
    }

    pass(score);  // Expected: 9 (all tests passed)
};

