mod platform {
    pub fn sleep(ms: i32) {
        extern "C" {
            fn usleep(usec: i32);
        }
        extern.usleep(ms * 1000);
    }
}

#[cfg(os = "windows")]
mod platform {
    pub fn sleep(ms: i32) {
        extern "system" {
            fn Sleep(ms: i32);
        }
        extern.Sleep(ms);
    }
}

// Common interface
pub fn sleep(ms: i32) {
    platform.sleep(ms);
```

