    common_logic();  // Duplicated
    linux_specific();
}

#[cfg(os = "windows")]
fn process() {
    common_logic();  // Duplicated
    windows_specific();
}

// Better
fn process() {
    common_logic();

    #[cfg(os = "linux")]
    linux_specific();

    #[cfg(os = "windows")]
    windows_specific();
```

